To reproduce, populate create an index with the following data:

```
DELETE test
PUT test
{
  "mappings": {
    "doc": {
      "properties": {
        "name": {
          "type": "keyword"
        },
        "category": {
          "type": "keyword"
        }
      }
    }
  }
}

PUT test/doc/1
{
  "name": "foo",
  "category": "A"
}

PUT test/doc/2
{
  "name": "foo",
  "category": "A"
}

PUT test/doc/3
{
  "name": "bar",
  "category": "A"
}

PUT test/doc/4
{
  "name": "baz",
  "category": "B"
}
```


The following statement returns expected results: 
```
POST _sql?format=text/plain
{
  "query": "SELECT count(DISTINCT name) as names, count(*) cnt, category FROM test GROUP BY category"
}

     names     |      cnt      |   category    
---------------+---------------+---------------
2.0            |3              |A              
1.0            |1              |B              
```

Please note, that category A has count 3 and category B has count of 1, while names have values of 1.0 and 2.0. However if we try to filter by names, the following request will not return us anything

```
POST _sql?format=text/plain
{
  "query": "SELECT count(DISTINCT name) as names, category FROM test GROUP BY category HAVING names = 2"
}
```

while this request returns us category A

```
POST _sql?format=text/plain
{
  "query": "SELECT count(DISTINCT name) as names, category FROM test GROUP BY category HAVING names = 3"
}

     names     |   category    
---------------+---------------
2.0            |A              

```
It is easy to see the reason for this by running translate. As you can see the bucket_selector is using `_count` instead of result of the coordinately aggregation `name`

```
POST _sql/translate
{
  "query": "SELECT count(DISTINCT name) as names, category FROM test GROUP BY category HAVING names = 3"
}

{
  "size" : 0,
  "_source" : false,
  "stored_fields" : "_none_",
  "aggregations" : {
    "groupby" : {
      "composite" : {
        "size" : 1000,
        "sources" : [
          {
            "593" : {
              "terms" : {
                "field" : "category",
                "missing_bucket" : true,
                "order" : "asc"
              }
            }
          }
        ]
      },
      "aggregations" : {
        "594" : {
          "cardinality" : {
            "field" : "name"
          }
        },
        "having.587" : {
          "bucket_selector" : {
            "buckets_path" : {
              "a0" : "_count"
            },
            "script" : {
              "source" : "InternalSqlScriptUtils.nullSafeFilter(InternalSqlScriptUtils.eq(params.a0,params.v0))",
              "lang" : "painless",
              "params" : {
                "v0" : 3
              }
            },
            "gap_policy" : "skip"
          }
        }
      }
    }
  }
}
```

